import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.anki.AnkiDroidJsAPI.ApiResult
import org.hamcrest.CoreMatchers.equalTo
import org.hamcrest.MatcherAssert.assertThat
import org.json.JSONObject
import org.junit.Test
import org.junit.runner.RunWith

@RunWith(AndroidJUnit4::class)
class AnkiDroidJsAPIFixTest : RobolectricTest() {

    @Test
    fun verifyReturnTypes() = runTest {
        val reviewer: Reviewer = startReviewer()
        val jsapi = reviewer.jsApi

        // Mock a simple request that returns an Int
        // We can use "cardQueue" as in the issue description
        // But we need a card setup.

        // Setup deck and note
        val models = col.notetypes
        val didA = addDeck("TestDeck", setAsSelected = true)
        val basic = models.byName(AnkiDroidApp.appResources.getString(R.string.basic_model_name))
        basic!!.put("did", didA)
        addNoteUsingBasicModel("Front", "Back")

        waitForAsyncTasksToComplete()

        val currentCard = reviewer.currentCard!!

        // Check cardQueue return type
        val queueResultJson = getDataFromRequest("cardQueue", jsapi)
        val queueJsonObj = JSONObject(queueResultJson)
        val queueValue = queueJsonObj.get("value")

        assertThat("Queue value should be an Int (number in JSON)", queueValue is Int, equalTo(true))
        assertThat(queueValue as Int, equalTo(currentCard.queue))

        // Check cardId return type (Long)
        val idResultJson = getDataFromRequest("cardId", jsapi)
        val idJsonObj = JSONObject(idResultJson)
        val idValue = idJsonObj.get("value")

        // JSONObject might parse Long as Integer if it fits, or Long.
        // Actually JSONObject.get returns Object.
        // If it's a number, it returns Integer, Long, Double.
        assertThat("Card ID value should be a Number", idValue is Number, equalTo(true))
        assertThat((idValue as Number).toLong(), equalTo(currentCard.id))

        // Check isActiveNetworkMetered (Boolean)
        val meteredResultJson = getDataFromRequest("isActiveNetworkMetered", jsapi)
        val meteredJsonObj = JSONObject(meteredResultJson)
        val meteredValue = meteredJsonObj.get("value")

        assertThat("Metered value should be a Boolean", meteredValue is Boolean, equalTo(true))
    }

    private fun startReviewer(): Reviewer {
        return ReviewerTest.startReviewer(this)
    }

    private fun jsApiContract(data: String = ""): ByteArray {
        return JSONObject().apply {
            put("version", "0.0.2")
            put("developer", "test@example.com")
            put("data", data)
        }.toString().toByteArray()
    }

    private suspend fun getDataFromRequest(
        methodName: String,
        jsAPI: AnkiDroidJsAPI,
        apiData: String = ""
    ): String {
        return jsAPI.handleJsApiRequest(methodName, jsApiContract(apiData), false)
            .decodeToString()
    }
}
